const items = $input.all();
const matches = items[0]?.json?.matches || [];

if (matches.length === 0) {
  return [{ json: { no_games_found: true } }];
}

const now = new Date();
const yesterday = new Date(now.getTime() - 24 * 60 * 60 * 1000);
const tomorrow = new Date(now.getTime() + 24 * 60 * 60 * 1000);

let recentMatches = matches.filter(match => {
  const matchDate = new Date(match.utcDate);
  return matchDate >= yesterday && matchDate <= tomorrow;
});

// TESTING FALLBACK: If manual testing yields no games in active rolling time zone frame,
// pull historical matches that have events logged so you don't receive an empty block
if (recentMatches.length === 0) {
  const loggedGames = matches.filter(m => m.status === 'FINISHED' || m.status === 'IN_PLAY' || m.status === 'PAUSED');
  recentMatches = loggedGames.length > 0 ? loggedGames.slice(-2) : matches.slice(0, 2);
}

return recentMatches.map(m => ({ json: m }));

const match = $input.all()[0]?.json;
if (!match || !match.homeTeam) return [];

const homeTeam = match.homeTeam.name || 'TBD';
const awayTeam = match.awayTeam.name || 'TBD';

const homeScore = match.score?.fullTime?.home !== null && match.score?.fullTime?.home !== undefined ? match.score.fullTime.home : '-';
const awayScore = match.score?.fullTime?.away !== null && match.score?.fullTime?.away !== undefined ? match.score.fullTime.away : '-';
const homeHT = match.score?.halfTime?.home !== null && match.score?.halfTime?.home !== undefined ? match.score.halfTime.home : '-';
const awayHT = match.score?.halfTime?.away !== null && match.score?.halfTime?.away !== undefined ? match.score.halfTime.away : '-';

let statusEmoji = '🏁 FT';
if (match.status === 'LIVE' || match.status === 'IN_PLAY') statusEmoji = '🔴 LIVE';
if (match.status === 'PAUSED') statusEmoji = '⏳ HT';
if (match.status === 'TIMED' || match.status === 'SCHEDULED') statusEmoji = '📅 Scheduled';

const stage = match.stage ? `| ${match.stage.replace(/_/g, ' ')}` : '';

let message = `🏆 *FIFA World Cup Update*\n\n`;
message += `⚽ *${homeTeam}*  ${homeScore} - ${awayScore}  *${awayTeam}*\n`;
message += `ℹ️ Status: ${statusEmoji} ${stage}\n`;

if (homeHT !== '-' || awayHT !== '-') {
  message += `⏳ Half-Time Score: [ ${homeHT} - ${awayHT} ]\n`;
}

let milestones = [];

// Extract detailed goals array populated on the singular match resource
if (match.goals && match.goals.length > 0) {
  match.goals.forEach(g => {
    const min = g.minute ? `${g.minute}'` : '';
    const extra = g.injuryTime ? `+${g.injuryTime}` : '';
    const typeModifier = g.type === 'PENALTY' ? ' (Penalty)' : g.type === 'OWN_GOAL' ? ' (OG)' : '';
    milestones.push(`🔸 Goal: ${g.scorer?.name || 'Unknown Player'} (${g.team?.name || ''}) ${min}${extra}${typeModifier}`);
  });
}

// Highlight exceptional disciplinary events and cards tracking
if (match.bookings && match.bookings.length > 0) {
  match.bookings.forEach(b => {
    if (b.card === 'RED' || b.card === 'YELLOW_RED') {
      milestones.push(`🟥 Red Card: ${b.player?.name || 'Unknown Player'} (${b.team?.name || ''}) ${b.minute || ''}'`);
    }
  });
}

if (match.penalties && match.penalties.length > 0) {
  match.penalties.forEach(p => {
    if (!p.scored) {
      milestones.push(`❌ Penalty Missed: ${p.player?.name || 'Unknown Player'} (${p.team?.name || ''}) ${p.minute || ''}'`);
    }
  });
}

if (milestones.length > 0) {
  message += `\n📝 *Match Events & Highlights:*\n${milestones.join('\n')}\n`;
} else if (['FINISHED', 'IN_PLAY', 'PAUSED'].includes(match.status)) {
  message += `\n📝 *Match Events:* No major events or goals logged yet.\n`;
}

return [{ json: { message: message } }];
